```go
import (
	"strconv"
)

func popcountInt(x int) int {
    count := 0
    for x > 0 {
        if x & 1 != 0 {
            count++
        }
        x >>= 1
    }
    return count
}

func countNumbersWithPopcountExactly(n int64, m0 int) int64 {
    if m0 < 0 {
        return 0
    }
    s := strconv.FormatInt(n, 2)
    digits := []byte(s)
    L := len(digits)

    dp := make([][][]int64, L)
    for i := range dp {
        dp[i] = make([][]int64, m0+1)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = -1
            dp[i][j][1] = -1
        }
    }

    var dfs func(int, int, int) int64
    dfs = func(pos int, count int, tight int) int64 {
        if pos == L {
            if count == m0 {
                return 1
            }
            return 0
        }
        if dp[pos][count][tight] != -1 {
            return dp[pos][count][tight]
        }
        res := int64(0)
        upBound := 1
        if tight == 1 {
            upBound = int(digits[pos] - '0')
        }
        for d := 0; d <= upBound; d++ {
            newCount := count
            if d == 1 {
                newCount = count + 1
                if newCount > m0 {
                    continue
                }
            }
            newTight := tight
            if tight == 1 {
                if d < upBound {
                    newTight = 0
                } else {
                    newTight = 1
                }
            }
            res += dfs(pos+1, newCount, newTight)
        }
        dp[pos][count][tight] = res
        return res
    }

    return dfs(0, 0, 1)
}

func solve(n int64, k int64) int64 {
    if k == 0 {
        if n >= 1 {
            return 1
        }
        return 0
    }

    dep := make([]int, 61)
    dep[1] = 0
    for i := 2; i <= 60; i++ {
        pc := popcountInt(i)
        dep[i] = 1 + dep[pc]
    }

    F := make([][]int64, 5)
    for i := 0; i < 5; i++ {
        F[i] = make([]int64, 0)
    }
    for i := 1; i <= 60; i++ {
        d := dep[i]
        if d < 5 {
            F[d] = append(F[d], int64(i))
        }
    }

    if k >= 1 && k <= 5 {
        T := F[k-1]
        total := int64(0)
        for _, m0 := range T {
            total += countNumbersWithPopcountExactly(n, int(m0))
        }
        if k == 1 {
            total--
        }
        return total
    }

    return 0
}
```

### Explanation
1. **Base Case Handling**: If k is 0, the solution checks if n is at least 1 (returning 1 if true, otherwise 0).
2. **Depth Precomputation**: The popcount and depth for numbers 1 to 60 are computed. The depth of a number is 1 plus the depth of its popcount.
3. **Set Construction**: Sets F₀ to F₄ are built, each containing numbers with depths 0 to 4 respectively.
4. **Digit DP for Counting**: For each number in the set Fₖ₋₁, the solution counts numbers in [0, n] with exactly that many 1s in binary. This uses memoized recursion to traverse digits while tracking 1s count and tight constraints.
5. **Adjustment for k = 1**: The count for numbers with popcount 1 includes 1, which has depth 0. Hence, it is subtracted from the total when k is 1.
6. **Result Calculation**: The total count of numbers with depth k is returned by summing counts for each valid popcount in Fₖ₋₁, adjusting for k = 1. For k > 5, it returns 0 as depths beyond 5 are impossible for numbers ≤ 10¹⁵.
